# Self-service run-as-admin autologon setup
# Run this file as Administrator

. "$PSScriptRoot\docker_autostart.ps1" 2>&1 | Out-Null; $reg = 'HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Winlogon'; if (-not (Test-Path $reg)) { New-Item -Path $reg -Force | Out-Null }; Set-ItemProperty -Path $reg -Name AutoAdminLogon -Value 1 -Type String; Set-ItemProperty -Path $reg -Name DefaultUserName -Value karma -Type String; Set-ItemProperty -Path $reg -Name DefaultDomainName -Value karma -Type String; if (Test-Path "$env:LOCALAPPDATA\Docker\autologon_pass.txt") { $p = Get-Content "$env:LOCALAPPDATA\Docker\autologon_pass.txt" -Raw; Set-ItemProperty -Path $reg -Name DefaultPassword -Value $p -Type String; Write-Host "Password loaded from secure file" } else { Write-Host "To set password: echo YOUR_PASSWORD | Set-Content '$env:LOCALAPPDATA\Docker\autologon_pass.txt'; Write-Host "Then re-run this script" }; Set-Service -Name com.docker.service -StartupType Automatic -Status Running -ErrorAction SilentlyContinue; Write-Host "Done"